// Extract clean fields from Gmail trigger output
const email = $input.first().json;
const config = $('2. Set — Config Values').item.json;

// Get sender details
const fromRaw = email.from?.text || email.from || '';
const senderEmail = fromRaw.match(/[\w.-]+@[\w.-]+\.[a-z]{2,}/i)?.[0] || 'user@example.com';
const senderName = fromRaw.replace(/<.*?>/, '').trim() || 'Unknown Sender';

// Get email content
const subject = email.subject || 'No Subject';
const body = email.text || email.snippet || email.body?.text || 'No email body found';
const receivedAt = email.date || new Date().toISOString();
const emailId = email.id || email.messageId || 'unknown';

// Truncate body to 3000 chars to stay within token limits
const bodyTruncated = body.substring(0, 3000);

return [{
  json: {
    emailId,
    senderEmail,
    senderName,
    subject,
    emailBody: bodyTruncated,
    receivedAt,
    companyName: config.companyName,
    sheetId: config.sheetId,
    sheetName: config.sheetName,
    slackBillingChannel: config.slackBillingChannel,
    slackTechChannel: config.slackTechChannel,
    slackSupportChannel: config.slackSupportChannel,
    supportEmail: config.supportEmail
  }
}];

