      "type": "string",
      "description": "One sentence summary of the complaint under 20 words"
    },
    "suggestedReply": {
      "type": "string",
      "description": "Professional empathetic reply under 80 words for the support agent to send"
    }
  },
  "required": ["urgencyScore", "department", "oneLineSummary", "suggestedReply"]
}

parameters.jsCode:
// Combine AI triage output with original email data
const aiOutput = $input.first().json.output;
const emailData = $('3. Code — Extract Email Fields').item.json;

const urgencyScore = aiOutput.urgencyScore || 0;
const department = aiOutput.department || 'General';
const oneLineSummary = aiOutput.oneLineSummary || 'No summary available';
const suggestedReply = aiOutput.suggestedReply || 'No reply generated';

// Set urgency label based on score
let urgencyLabel = 'Low';
if (urgencyScore >= 8) urgencyLabel = 'CRITICAL';
else if (urgencyScore >= 6) urgencyLabel = 'High';
else if (urgencyScore >= 4) urgencyLabel = 'Medium';

// Decide which Slack channel based on department
let slackChannel = emailData.slackSupportChannel;
if (department === 'Billing') slackChannel = emailData.slackBillingChannel;
if (department === 'Technical') slackChannel = emailData.slackTechChannel;

// Format received date nicely
const receivedDate = emailData.receivedAt
  ? new Date(emailData.receivedAt).toISOString().replace('T', ' ').substring(0, 16)
  : new Date().toISOString().replace('T', ' ').substring(0, 16);

return [{
  json: {
    emailId: emailData.emailId,
    senderEmail: emailData.senderEmail,
    senderName: emailData.senderName,
    subject: emailData.subject,
    emailBody: emailData.emailBody,
    receivedDate,
    supportEmail: emailData.supportEmail,
    sheetId: emailData.sheetId,
    sheetName: emailData.sheetName,
    urgencyScore,
    urgencyLabel,
    department,
    oneLineSummary,
    suggestedReply,
    slackChannel,
    loggedAt: new Date().toISOString().replace('T', ' ').substring(0, 16)
  }
}];

